class Command(BaseCommand):
    help = "DB에 사전 정의된 퀴즈 문제를 입력합니다."

    def add_arguments(self, parser):
        parser.add_argument(
            "--clear",
            action="store_true",
            help="기존 preset 문제를 모두 삭제 후 재입력",
        )

    def handle(self, *args, **options):
        if options["clear"]:
            deleted, _ = Question.objects.filter(source="preset").delete()
            self.stdout.write(self.style.WARNING(f"기존 preset 문제 {deleted}개 삭제"))

        created = 0
        for q in QUESTIONS:
            _, is_new = Question.objects.get_or_create(
                category=q["category"],
                difficulty=q["difficulty"],
                question_text=q["question_text"],
                defaults={
                    "hint": q.get("hint", ""),
                    "answer_key": q.get("answer_key", ""),
                    "code_snippet": q.get("code_snippet") or None,
                    "source": "preset",
                },
            )
            if is_new:
                created += 1

        total = Question.objects.filter(source="preset").count()
        self.stdout.write(
            self.style.SUCCESS(
                f"완료: {created}개 새로 추가 / 전체 preset 문제 {total}개"
            )
        )
